# ----------------------------
# TOTP (RFC 6238) minimal implementation
# ----------------------------
def _b32decode_nopad(s: str) -> bytes:
    s = s.strip().replace(" ", "").upper()
    pad = "=" * ((8 - (len(s) % 8)) % 8)
    return base64.b32decode(s + pad, casefold=True)

def totp_now(secret_b32: str, step: int = 30, digits: int = 6, t: int | None = None) -> str:
    if t is None:
        t = int(time.time())
    counter = int(t // step)
    key = _b32decode_nopad(secret_b32)
    msg = counter.to_bytes(8, "big")
    digest = hmac.new(key, msg, hashlib.sha1).digest()
    offset = digest[-1] & 0x0F
    code_int = int.from_bytes(digest[offset:offset + 4], "big") & 0x7FFFFFFF
    code = code_int % (10 ** digits)
    return str(code).zfill(digits)

def verify_totp(secret_b32: str, otp: str, step: int = 30, digits: int = 6, window: int = 1) -> bool:
    otp = (otp or "").strip()
    if not otp.isdigit() or len(otp) != digits:
        return False
    now = int(time.time())
    for w in range(-window, window + 1):
        if hmac.compare_digest(totp_now(secret_b32, step=step, digits=digits, t=now + w * step), otp):
            return True
    return False

# ----------------------------
# Auth helpers
# ----------------------------
def get_user(username: str):
    return USERS.get(username)

def login_user(username: str, mfa_completed: bool):
    session.clear()
    session["username"] = username
    session["authenticated"] = True
    session["mfa_completed"] = bool(mfa_completed)
    session["login_ts"] = int(time.time())

def logout_user():
    session.clear()

def is_logged_in() -> bool:
    return bool(session.get("authenticated")) and bool(session.get("username"))

def is_fully_authenticated() -> bool:
    if not is_logged_in():
        return False
    user = get_user(session.get("username"))
    if not user:
        return False
    if user.get("mfa_enabled"):
        return bool(session.get("mfa_completed"))
    return True

def require_full_auth():
    if not is_logged_in():
        return redirect(url_for("login"))
    user = get_user(session.get("username"))
    if not user:
        logout_user()
        return redirect(url_for("login"))
    if user.get("mfa_enabled") and not session.get("mfa_completed"):
        return redirect(url_for("mfa"))
    return None

