@app.route("/", methods=["GET"])
def index():
    if is_fully_authenticated():
        return redirect(url_for("dashboard"))
    if is_logged_in():
        return redirect(url_for("mfa"))
    return redirect(url_for("login"))

@app.route("/login", methods=["GET", "POST"])
def login():
    if request.method == "GET":
        return render_template_string(LOGIN_TEMPLATE, error=None)

    username = (request.form.get("username") or "").strip()
    password = request.form.get("password") or ""

    user = get_user(username)
    if not user or not check_password_hash(user["password_hash"], password):
        return render_template_string(LOGIN_TEMPLATE, error="Invalid username or password"), 401

    if user.get("mfa_enabled"):
        login_user(username, mfa_completed=False)
        return redirect(url_for("mfa"))

    login_user(username, mfa_completed=True)
    return redirect(url_for("dashboard"))

@app.route("/mfa", methods=["GET", "POST"])
def mfa():
    if not is_logged_in():
        return redirect(url_for("login"))

    username = session.get("username")
    user = get_user(username)
    if not user:
        logout_user()
        return redirect(url_for("login"))

    if not user.get("mfa_enabled"):
        session["mfa_completed"] = True
        return redirect(url_for("dashboard"))

    if request.method == "GET":
        return render_template_string(OTP_TEMPLATE, error=None)

    otp = request.form.get("otp") or ""
    secret_b32 = user.get("mfa_secret")
    if not secret_b32:
        logout_user()
        return render_template_string(LOGIN_TEMPLATE, error="MFA misconfigured; contact support"), 403

    if not verify_totp(secret_b32, otp):
        return render_template_string(OTP_TEMPLATE, error="Invalid OTP"), 401

    session["mfa_completed"] = True
    return redirect(url_for("dashboard"))

@app.route("/dashboard", methods=["GET"])
def dashboard():
    gate = require_full_auth()
    if gate is not None:
        return gate
    username = session.get("username")
    return render_template_string(
        DASHBOARD_TEMPLATE,
        username=username,
        authenticated=bool(session.get("authenticated")),
        mfa_completed=bool(session.get("mfa_completed")),
    )

@app.route("/logout", methods=["POST"])
def logout():
    logout_user()
    return redirect(url_for("login"))

