@app.route("/api/login", methods=["POST"])
def api_login():
    data = request.get_json(silent=True) or {}
    username = (data.get("username") or "").strip()
    password = data.get("password") or ""
    otp = (data.get("otp") or "").strip()

    user = get_user(username)
    if not user or not check_password_hash(user["password_hash"], password):
        return jsonify({"ok": False, "error": "invalid_credentials"}), 401

    if user.get("mfa_enabled"):
        if not otp:
            return jsonify({"ok": False, "error": "mfa_required"}), 401
        secret_b32 = user.get("mfa_secret")
        if not secret_b32 or not verify_totp(secret_b32, otp):
            return jsonify({"ok": False, "error": "invalid_otp"}), 401

    token = secrets.token_urlsafe(32)
    return jsonify({"ok": True, "token": token, "username": username, "mfa": bool(user.get("mfa_enabled"))})

@app.route("/api/direct-login", methods=["POST"])
def api_direct_login():
    data = request.get_json(silent=True) or {}
    username = (data.get("username") or "").strip()
    password = data.get("password") or ""

    user = get_user(username)
    if not user or not check_password_hash(user["password_hash"], password):
        return jsonify({"ok": False, "error": "invalid_credentials"}), 401

    token = secrets.token_urlsafe(32)
    return jsonify({"ok": True, "token": token, "username": username, "mfa_skipped": True})

# Optional: API key based direct login for integrations
@app.route("/api/direct-login/apikey", methods=["POST"])
def api_direct_login_apikey():
    data = request.get_json(silent=True) or {}
    client_id = (data.get("client_id") or "").strip()
    api_key = data.get("api_key") or ""

    client = API_CLIENTS.get(client_id)
    if not client or not check_password_hash(client["api_key_hash"], api_key):
        return jsonify({"ok": False, "error": "invalid_client"}), 401

    username = client.get("username")
    if not username or username not in USERS:
        return jsonify({"ok": False, "error": "invalid_mapping"}), 403

    token = secrets.token_urlsafe(32)
    return jsonify({"ok": True, "token": token, "username": username, "mfa_skipped": True, "client_id": client_id})

